Code:
public boolean canBalance(int[] nums) {
    int totalSum = 0;
    for(int num: nums) {
        totalSum += num;
    }

    int leftSum = 0;
    for(int i=0; i< nums.length; i++) {
        totalSum -= nums[i];
        if(leftSum == totalSum) {
            return true;
        }
        leftSum += nums[i];
    }
    return false;
}

